import os
for root, dirs, files in os.walk('/workspace'):
    # Skip memory dirs
    dirs[:] = [d for d in dirs if d != 'memory' and not d.startswith('.')]
    depth = root.replace('/workspace', '').count('/')
    if depth > 3:
        continue
    print(root)
    for f in files:
        print(f"  {f}")
